// And groups predicates with the AND operator between them.
func And(predicates ...predicate.LpAccount) predicate.LpAccount {
	return predicate.LpAccount(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.LpAccount) predicate.LpAccount {
	return predicate.LpAccount(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.LpAccount) predicate.LpAccount {
	return predicate.LpAccount(sql.NotPredicates(p))
}
